SELECT tag_name, tag_description, tag_type
FROM health_tags
WHERE health_id = 1;

SELECT policy_id, effectiveness_score, evaluation_method
FROM policy_effectiveness
WHERE effectiveness_score < 0.5 AND evaluation_method = 'Expert review';

SELECT effectiveness_score
FROM health_effectiveness
WHERE health_id = 2;

SELECT country_name, area
FROM countries
WHERE area = (SELECT MIN(area) FROM countries WHERE area > 0);

SELECT AVG(population) AS Average_Population
FROM countries
WHERE region_name = 'Asia';

SELECT country_name, region_name, government_type
FROM countries
WHERE population < 10000000 AND government_type = 'democracy';
